export const axiomApprovalReviewSpecs = [
  {
    "capability": "extract_receipt_fields",
    "required": true,
    "binds": [],
    "modes": [
      "not_required if internal_assigned_worker"
    ],
    "input": [
      "receipt_id",
      "worker_id"
    ]
  }
];

export function approvalReviewSpecFor(capabilityKey) {
  return axiomApprovalReviewSpecs.find((item) => item.capability === capabilityKey) || null;
}

export function createApprovalReviewModel(capabilityKey, request = {}) {
  const spec = approvalReviewSpecFor(capabilityKey);
  if (!spec) {
    return {
      ok: false,
      capability: capabilityKey,
      error: "unknown_capability",
      fields: [],
      missing: [],
      spec: null,
    };
  }

  const approval = request.approval || {};
  const fields = spec.binds.map((field) => {
    const value = approval[field] ?? request[field] ?? request.input?.[field] ?? "";
    return {
      name: field,
      value,
      present: value !== undefined && value !== null && value !== "",
      required: true,
    };
  });
  const missing = fields.filter((field) => !field.present).map((field) => field.name);

  return {
    ok: missing.length === 0,
    capability: capabilityKey,
    title: `Review approval for ${capabilityKey}`,
    fields,
    missing,
    modes: spec.modes,
    spec,
  };
}

export function assertApprovalReviewComplete(model) {
  if (!model?.ok) {
    throw new Error(`Axiom approval review is missing required field(s): ${(model?.missing || []).join(", ")}`);
  }
  return model;
}
